module challenge::vault {
    struct Vault<T> has key {
        owner: address,
        data: T,
    }

    public fun new<T>(owner: address, data: T): Vault<T> {
        [[SLOT vault_construct]]
    }

    public fun owner<T>(vault: &Vault<T>): address {
        vault.owner
    }

    public fun borrow<T>(vault: &Vault<T>): &T {
        [[SLOT borrow_ret]]
    }

    public fun update<T>(vault: &mut Vault<T>, new_data: T) {
        vault.data = new_data;
    }

    public fun unwrap<T>(vault: Vault<T>): T {
        let Vault { owner: _, data } = vault;
        data
    }
}

module challenge::access {
    struct AdminCap has key, store {
        id: u64,
    }

    public fun mint(id: u64): AdminCap {
        AdminCap { id }
    }

    public fun verify(_cap: &AdminCap): bool {
        true
    }
}

module challenge::solution {
    use challenge::vault::{Self, Vault};
    use challenge::access::{Self, AdminCap};

    const UNAUTHORIZED: u64 = 1;

    public fun create_vault<T>(owner: address, data: T): Vault<T> {
        vault::new(owner, data)
    }

    public fun read_vault<T>(vault: &Vault<T>, reader: address): &T {
        assert!([[SLOT auth_check]], UNAUTHORIZED);
        vault::borrow(vault)
    }

    public fun update_vault<T>(vault: &mut Vault<T>, cap: &AdminCap, new_data: T) {
        assert!([[SLOT verify_check]], UNAUTHORIZED);
        vault::update(vault, new_data);
    }

    public fun destroy_vault<T>(vault: Vault<T>, cap: &AdminCap): T {
        assert!(access::verify(cap), UNAUTHORIZED);
        vault::unwrap(vault)
    }
}
